      FlutterError.onError = (FlutterErrorDetails details) {
        l.log(
          LogLevel.fatal,
          'APP',
          'FlutterError',
          error: details.exception,
          stackTrace: details.stack,
          fields: {
            'library': details.library,
            'context': details.context?.toDescription(),
            'informationCollector': details.informationCollector != null ? 'present' : null,
          },
        );
        FlutterError.presentError(details);
      };
    }

    if (enablePlatformErrorHook) {
      PlatformDispatcher.instance.onError = (error, stack) {
        l.log(LogLevel.fatal, 'APP', 'PlatformDispatcher.onError', error: error, stackTrace: stack);
        return false;
      };
    }

    if (enableHttpOverrides) {
      HttpOverrides.global = _LoggingHttpOverrides(l);
    }
  }
}

