class ExampleAuthService {
  ExampleAuthService({required this.client, AuthLogger? authLogger}) : authLogger = authLogger ?? AuthLogger();

  final http.Client client;
  final AuthLogger authLogger;

  Future<http.Response> login({
    required String email,
    required String password,
  }) {
    return authLogger.flow(
      'login',
      details: {
        'email': email,
        'password': password,
      },
      action: () async {
        final uri = Uri.parse('https://example.com/login');
        final resp = await client.post(
          uri,
          headers: {'content-type': 'application/json'},
          body: jsonEncode({'email': email, 'password': password}),
        );
        return resp;
      },
    );
  }
}

